#include <iostream>
#include <string>

int main() {
    std::cout << "=== Spawning Enemies ===" << std::endl;

    // For loop: spawn 5 enemies
    for (int i = 0; i < 5; i++) {
        std::cout << "Spawned enemy #" << (i + 1) << std::endl;
    }

    std::cout << "\n=== Inventory Items ===" << std::endl;
    std::string items[] = {"Health Potion", "Mana Potion", "Sword", "Shield", "Key"};

    // Loop through array
    for (int i = 0; i < 5; i++) {
        std::cout << "Item " << (i + 1) << ": " << items[i] << std::endl;
    }

    std::cout << "\n=== Leveling Up ===" << std::endl;
    int playerLevel = 1;

    // Level up 5 times
    for (int level = 1; level <= 5; level++) {
        std::cout << "Level " << level << " → Health +10, Attack +5" << std::endl;
    }

    std::cout << "\n=== Countdown ===" << std::endl;
    // Countdown from 10
    for (int i = 10; i > 0; i--) {
        std::cout << i << "..." << std::endl;
    }
    std::cout << "GO!" << std::endl;

    std::cout << "\n=== Nested Loops (Grid) ===" << std::endl;
    // 3x3 grid
    for (int row = 0; row < 3; row++) {
        for (int col = 0; col < 3; col++) {
            std::cout << "[" << row << "][" << col << "] ";
        }
        std::cout << std::endl;
    }

    return 0;
}

